// UreTech Email Signature — handler event-based (OnNewMessageCompose).
// Innestato sul sample ufficiale Microsoft "outlook-set-signature".
//
// Inserisce la firma aziendale sotto il testo (nuove/risposte/inoltri), su
// Outlook web/Windows/Mac e mobile iOS/Android. Client-side: zero porte inbound.
//
// Accorgimenti:
//  - disableClientSignatureAsync PRIMA di setSignatureAsync -> evita firma doppia (#5483/#6402)
//  - marker invisibile URE-SIG-v1 nel corpo -> discriminante per eventuale transport rule (Android #6244)
//  - immagini = URL pubblici su uretech.it (nessun base64/CID da allegare)
//  - notifica visibile SOLO in caso di errore (in successo: niente, firma pulita)

var URE_MARKER = "URE-SIG-v1";

// Mansioni per casella (Title non è esposto lato client; mappa statica per le 4 caselle).
var URE_TITLES = {
  "f.fontanella@uretech.it": "Support Specialist",
};

function ure_isValid(s) {
  return s !== null && s !== undefined && s !== "";
}

// Firma grafica completa UreTech con campi dinamici. Immagini = URL pubblici.
function ure_buildSignature(displayName, email) {
  var name = ure_isValid(displayName) ? displayName : "UreTech";
  var mail = ure_isValid(email) ? email : "info@uretech.it";
  var title = URE_TITLES[mail.toLowerCase()] || "";
  var marker = '<span style="display:none;font-size:0;line-height:0;color:#fff">' + URE_MARKER + "</span>";

  var tpl =
`<table class="us w" cellpadding="0" cellspacing="0" border="0" width="520" background="https://www.uretech.it/wp-content/uploads/2026/03/grid-tile.png" style="width:520px;border-collapse:collapse;font-family:'Helvetica Neue',Arial,sans-serif;color:#0F172A;background-color:#fff;background-image:url('https://www.uretech.it/wp-content/uploads/2026/03/grid-tile.png');background-repeat:repeat"><tr><td colspan="3" style="padding:0 0 14px;border-bottom:1px solid #0F172A"><table width="100%" style="border-collapse:collapse"><tr><td class="ch" style="font-family:Consolas,monospace;font-size:10px;font-weight:bold;letter-spacing:2px;color:#0F172A;text-transform:uppercase">U'RE&nbsp;TECH&nbsp;<span class="m" style="color:#94A3B8">/&nbsp;WEB&nbsp;AGENCY&nbsp;&amp;&nbsp;SOFTWARE&nbsp;HOUSE</span></td><td align="right" class="m" style="font-family:Consolas,monospace;font-size:10px;letter-spacing:2px;color:#94A3B8;text-transform:uppercase">PARTNER&nbsp;DIGITALE</td></tr></table></td></tr><tr><td valign="top" width="72" style="width:72px;padding:14px 0 0"><img src="https://www.uretech.it/wp-content/uploads/2026/03/accent-uretech.png" alt="" height="56" style="display:block;height:56px;width:auto;border:0"></td><td width="12" style="width:12px;font-size:0">&nbsp;</td><td valign="top" style="padding:14px 0 0"><div class="n" style="font-size:19px;line-height:23px;font-weight:800;letter-spacing:-0.3px;color:#0F172A">{{DISPLAYNAME}}</div><div class="t m" style="font-family:Consolas,monospace;font-size:10px;line-height:13px;letter-spacing:1px;text-transform:uppercase;padding-top:5px;color:#64748B">{{TITLE}}</div><table style="border-collapse:collapse;margin-top:12px"><tr><td style="padding-right:9px;line-height:0"><img src="https://www.uretech.it/wp-content/uploads/2026/03/icon-mail.png" alt="" width="13" height="13" style="display:block;border:0"></td><td class="ca" style="font-family:Consolas,monospace;font-size:12px;line-height:21px;font-weight:500"><a href="mailto:{{EMAIL}}" style="color:#0F172A;text-decoration:none">{{EMAIL}}</a></td></tr><tr><td style="padding-right:9px;line-height:0"><img src="https://www.uretech.it/wp-content/uploads/2026/03/icon-phone.png" alt="" width="13" height="13" style="display:block;border:0"></td><td class="ca" style="font-family:Consolas,monospace;font-size:12px;line-height:21px;font-weight:500"><a href="tel:+390282860103" style="color:#0F172A;text-decoration:none">+39 02 8286 0103</a></td></tr><tr><td style="padding-right:9px;line-height:0"><img src="https://www.uretech.it/wp-content/uploads/2026/03/icon-web.png" alt="" width="13" height="13" style="display:block;border:0"></td><td class="ca" style="font-family:Consolas,monospace;font-size:12px;line-height:21px;font-weight:500"><a href="https://www.uretech.it" style="color:#0F172A;text-decoration:none">www.uretech.it</a></td></tr></table></td></tr><tr><td colspan="3" style="padding:16px 0 0"><table width="100%" style="border-collapse:collapse;border-top:1px solid #E2E8F0"><tr><td class="cf" style="font-family:Consolas,monospace;font-size:10px;font-weight:bold;letter-spacing:1.6px;text-transform:uppercase;padding-top:12px;color:#0F172A"><span style="color:#EA88DE">&#9612;</span>&nbsp;MILANO&nbsp;&nbsp;<span style="color:#CBD5E1">/</span>&nbsp;&nbsp;BOLOGNA&nbsp;&nbsp;<span style="color:#CBD5E1">/</span>&nbsp;&nbsp;ROMA</td><td align="right" class="m" style="font-family:Consolas,monospace;font-size:9px;color:#94A3B8;letter-spacing:1.6px;text-transform:uppercase;padding-top:12px">P.IVA&nbsp;04134771205</td></tr><tr><td colspan="2" class="m" style="font-family:Consolas,monospace;font-size:10px;line-height:16px;color:#64748B;letter-spacing:1px;padding-top:6px;text-transform:uppercase"><span style="color:#94A3B8">PARTNER&nbsp;&raquo;</span>&nbsp;&nbsp;WordPress&nbsp;&middot;&nbsp;Wix&nbsp;&middot;&nbsp;Odoo&nbsp;&middot;&nbsp;Google&nbsp;&middot;&nbsp;Cloudflare&nbsp;&middot;&nbsp;Adobe&nbsp;&middot;&nbsp;Aruba</td></tr></table></td></tr><tr><td colspan="3" style="padding:14px 0 0"><table width="100%" style="border-collapse:collapse;border-top:1px dashed #CBD5E1"><tr><td class="m" style="font-family:Consolas,monospace;font-size:9px;line-height:14px;color:#94A3B8;letter-spacing:0.5px;padding-top:10px"><span style="color:#64748B;font-weight:bold;text-transform:uppercase;letter-spacing:1.6px">[ Riservatezza ]</span>&nbsp;&nbsp;Messaggio riservato al destinatario indicato. Ogni uso o diffusione non autorizzati sono vietati. Se ricevuto per errore, eliminare e avvisare il mittente.&nbsp;<span style="color:#CBD5E1">//</span>&nbsp;Non costituisce proposta contrattuale vincolante.</td></tr></table></td></tr></table>`;

  return marker + tpl
    .split("{{DISPLAYNAME}}").join(name)
    .split("{{TITLE}}").join(title)
    .split("{{EMAIL}}").join(mail);
}

function ure_setSignature(eventObj) {
  var item = Office.context.mailbox.item;
  item.from.getAsync(function (res) {
    var name = "UreTech";
    var mail = "";
    if (res && res.status === "succeeded" && res.value) {
      name = res.value.displayName || name;
      mail = res.value.emailAddress || "";
    } else {
      var p = Office.context.mailbox.userProfile;
      name = (p && p.displayName) || name;
      mail = (p && p.emailAddress) || "";
    }
    Office.context.mailbox.item.body.setSignatureAsync(
      ure_buildSignature(name, mail),
      { coercionType: "html", asyncContext: eventObj },
      function (asyncResult) {
        if (asyncResult.status !== "succeeded") {
          // Solo in caso di errore: notifica visibile (debug).
          try {
            Office.context.mailbox.item.notificationMessages.addAsync(
              "ure_err",
              {
                type: "errorMessage",
                message: "UreTech firma: " + (asyncResult.error && asyncResult.error.message),
              },
              function () { asyncResult.asyncContext.completed(); }
            );
            return;
          } catch (e) {
            /* fallthrough */
          }
        }
        asyncResult.asyncContext.completed();
      }
    );
  });
}

// Handler associato all'evento (FunctionName="checkSignature" nel manifest).
function checkSignature(eventObj) {
  var item = Office.context.mailbox.item;
  if (item && typeof item.disableClientSignatureAsync === "function") {
    // Disabilita la firma nativa/roaming per evitare doppioni, poi inserisce la nostra.
    item.disableClientSignatureAsync(function () {
      ure_setSignature(eventObj);
    });
  } else {
    ure_setSignature(eventObj);
  }
}

Office.actions.associate("checkSignature", checkSignature);
